<?php function solve($m,$k){$R=count($m);$C=count($m[0]);$best=-1000000000;for($top=0;$top<$R;$top++){$s=array_fill(0,$C,0);for($bot=$top;$bot<$R;$bot++){for($c=0;$c<$C;$c++)$s[$c]+=$m[$bot][$c];$pre=[0];$cur=0;foreach($s as $x){$cur+=$x;$target=$cur-$k;$i=0;while($i<count($pre)&&$pre[$i]<$target)$i++;if($i<count($pre))$best=max($best,$cur-$pre[$i]);$j=0;while($j<count($pre)&&$pre[$j]<$cur)$j++;array_splice($pre,$j,0,[$cur]);}}}return $best;}$d=preg_split('/\s+/',trim(stream_get_contents(STDIN)));if(count($d)&&$d[0]!==""){$idx=0;$t=intval($d[$idx++]);$out=[];for($tc=0;$tc<$t;$tc++){$r=intval($d[$idx++]);$c=intval($d[$idx++]);$m=[];for($i=0;$i<$r;$i++){$row=[];for($j=0;$j<$c;$j++)$row[]=intval($d[$idx++]);$m[]=$row;}$k=intval($d[$idx++]);$out[]=strval(solve($m,$k));}echo implode("\n\n",$out);}
?>
